cypher:
MATCH (keanu:Person {name: "Keanu Reeves"})-[:ACTED_IN]->(matrix:Movie {title: "The Matrix"}),       (sandra:Person {name: "Sandra Bullock"})-[:ACTED_IN]->(speed:Movie {title: "Speed"})
WHERE (keanu)-[:DIRECTED]->(:Movie {title: "The Matrix"}) AND (sandra)-[:DIRECTED]->(:Movie {title: "Speed"})
RETURN
  keanu, {  
    matrix: {  
      roles: keanu.roles IN matrix.roles? TRUE : false,       
      rating: matrix.rating  
    }  
  }),       (sandra), {  
    speed: {  
      roles: sandra.roles IN speed.roles? TRUE : false,       
      rating: speed.rating  
    }  
  }
ORDER BY keanu.rating DESC, speed.rating DESC
